// ===== ACTOR NAME RETRIEVAL (SDK-BASED, OPTIMIZED) =====

// OPTIMIZED: Fast FString to C-string conversion without dynamic allocation
// Uses stack buffer for conversion - NO new/delete calls (avoids heap fragmentation)
static const char* FStringToCString_Optimized(const void* FStringPtr, char* OutputBuffer, size_t BufferSize)
{
	if (!FStringPtr || !OutputBuffer || BufferSize < 2)
		return "";
	
	try
	{
		// FString structure: pointer at +0x00, length at +0x08
		const wchar_t* StrData = *(const wchar_t**)((uintptr_t)FStringPtr);
		const int32* StrLen = (const int32*)((uintptr_t)FStringPtr + 0x08);
		
		if (!StrData || !StrLen || *StrLen <= 0)
		{
			OutputBuffer[0] = '\0';
			return OutputBuffer;
		}
		
		// Fast conversion wchar_t to ASCII (most player names are ASCII anyway)
		size_t outIdx = 0;
		int maxLen = (*StrLen < (int)BufferSize - 1) ? *StrLen : (int)BufferSize - 1;
		
		for (int i = 0; i < maxLen && StrData[i] != L'\0'; i++)
		{
			wchar_t wc = StrData[i];
			if (wc < 128)  // ASCII fast path
				OutputBuffer[outIdx++] = (char)wc;
			else if (outIdx < BufferSize - 1)
				OutputBuffer[outIdx++] = '?';
		}
		
		OutputBuffer[outIdx] = '\0';
		return OutputBuffer;
	}
	catch (...)
	{
		OutputBuffer[0] = '\0';
		return OutputBuffer;
	}
}

// Get PlayerState from an Actor (APawn)
// APawn has PlayerState at offset 0x0240
extern "C" void* SDK_GetPlayerStateFromActor(void* Actor)
{
	try
	{
		if (!Actor) return nullptr;
		
		// Try to get PlayerState from APawn offset 0x0240
		void** PlayerStatePtr = (void**)((uintptr_t)Actor + 0x0240);
		void* PlayerState = *PlayerStatePtr;
		
		return PlayerState;  // May be nullptr for CHARACTER_BATTLE
	}
	catch (...)
	{
		return nullptr;
	}
}

// Get player name from PlayerState (OPTIMIZED - like zero1 with both name fields)
// PlayerName is an FString at offset 0x0350 (848) in APlayerState
// PlayerNamePrivate is an FString at offset 0x0300 (768) in APlayerState
extern "C" const char* SDK_GetPlayerName(void* PlayerState)
{
	if (!PlayerState) return "";
	
	try
	{
		static thread_local char nameBuffer[256];
		nameBuffer[0] = '\0';
		int pos = 0;
		
		// Get FString Playername at offset 0x0350 (like zero1)
		const void* PlayerNamePtr = (const void*)((uintptr_t)PlayerState + 0x0350);
		char tempName[128] = {0};
		FStringToCString_Optimized(PlayerNamePtr, tempName, sizeof(tempName));
		
		// Get FString PlayerNamePrivate at offset 0x0300
		const void* PlayerNamePrivatePtr = (const void*)((uintptr_t)PlayerState + 0x0300);
		char tempNamePrivate[128] = {0};
		FStringToCString_Optimized(PlayerNamePrivatePtr, tempNamePrivate, sizeof(tempNamePrivate));
		
		// Combine like zero1: "Playername (NamePrivate)"
		if (tempName[0] != '\0') {
			pos = snprintf(nameBuffer, sizeof(nameBuffer), "%s", tempName);
		}
		
		if (tempNamePrivate[0] != '\0' && pos < (int)sizeof(nameBuffer) - 20) {
			snprintf(nameBuffer + pos, sizeof(nameBuffer) - pos, " (%s)", tempNamePrivate);
		}
		
		// Fallback to NamePrivate only if Playername is empty
		if (nameBuffer[0] == '\0' && tempNamePrivate[0] != '\0') {
			snprintf(nameBuffer, sizeof(nameBuffer), "%s", tempNamePrivate);
		}
		
		return (nameBuffer[0] != '\0') ? nameBuffer : "";
	}
	catch (...)
	{
		return "";
	}
}

// Get complete actor display name with suffixes (OPTIMIZED - no std::string, uses stack buffer)
extern "C" const char* SDK_GetActorDisplayName(void* Actor, bool isMySelf, bool isDying)
{
	if (!Actor) return "Unknown";
	
	static thread_local char displayBuffer[256];
	displayBuffer[0] = '\0';
	
	try
	{
		const char* baseName = "Unknown";
		
		// Check if this is a CharacterOutGame (lobby character) vs other types
		AActor* ActorPtr = (AActor*)Actor;
		if (ActorPtr && ActorPtr->Class)
		{
			std::string className = ActorPtr->Class->GetName();
			
			// For CharacterOutGame/ACharacterOutGame - use lookup table (faster, no PropertyState lookup)
			if (className == "CharacterOutGame" || className == "ACharacterOutGame")
			{
				uint8 characterID = SDK_GetCharacterOutGameId(Actor);
				baseName = SDK_GetCharacterName(characterID);
			}
			else
			{
				// For CHARACTER_BATTLE and others - try PlayerState
				void* PlayerState = SDK_GetPlayerStateFromActor(Actor);
				if (PlayerState)
				{
					const char* playerName = SDK_GetPlayerName(PlayerState);
					if (playerName && playerName[0] != '\0')
						baseName = playerName;
				}
			}
		}
		
		// Build final name with suffixes directly in buffer (no intermediate allocations)
		int pos = snprintf(displayBuffer, sizeof(displayBuffer), "%s",  baseName);
		
		if (isMySelf && pos < (int)sizeof(displayBuffer) - 10)
			pos += snprintf(displayBuffer + pos, sizeof(displayBuffer) - pos, " (Me)");
		
		if (isDying && pos < (int)sizeof(displayBuffer) - 10)
			snprintf(displayBuffer + pos, sizeof(displayBuffer) - pos, " (Dying)");
		
		return displayBuffer;
	}
	catch (...)
	{
		snprintf(displayBuffer, sizeof(displayBuffer), "Unknown");
		return displayBuffer;
	}
}

