// ===== DRAWING FUNCTIONS FOR ESP =====

/**
 * @brief Update actor cache with throttling (like zero1's 200ms enumeration)
 * 
 * Enumerates actors only if ENUMERATION_THROTTLE_MS has passed since last enumeration.
 * Uses double-buffering: g_ActorsToProcess is filled, then swapped with g_ActorsForRendering.
 */
static void SDK_UpdateActorCache()
{
	uint64_t currentTime = GetCurrentTimeMs();
	
	// Check if it's time to enumerate (200ms throttle like zero1)
	if ((currentTime - g_LastEnumerationTime) < ENUMERATION_THROTTLE_MS)
	{
		// Reuse cached actors from last enumeration - NO NEW ENUMERATION NEEDED
		// Render thread reads from g_ActorsForRendering which was filled 200ms ago
		return;
	}
	
	// 200ms passed - time to enumerate actors (heavyweight operation in separate logic)
	g_LastEnumerationTime = currentTime;
	
	try
	{
		// Get world
		UWorld* World = UWorld::GetWorld();
		if (!World || !World->PersistentLevel)
			return;
		
		// Enumerate actors (this is the expensive operation, but only every 200ms)
		const TArray<AActor*>& AllActors = World->PersistentLevel->Actors;
		
		// Clear temporary buffers
		std::vector<CachedActor> newActorList;
		std::vector<CachedActor> newItemList;  // SEPARATE LIST FOR ITEMS
		newActorList.reserve(100);  // Pre-allocate for typical count
		newItemList.reserve(50);    // Pre-allocate for typical items count
		
		for (int i = 0; i < AllActors.Num(); i++)
		{
			AActor* Actor = AllActors[i];
			
			// Safety: Skip null or default objects
			if (!Actor) continue;
			if (Actor->IsDefaultObject()) continue;
			
			// Additional safety: Try to access Class - if it crashes, skip
			SDK::UClass* ActorClass = nullptr;
			try
			{
				ActorClass = Actor->Class;
				if (!ActorClass) continue;
			}
			catch (...)
			{
				continue;  // Skip if Class is inaccessible
			}
			
			// Get class name
			std::string ClassName = "";
			try
			{
				ClassName = ActorClass->GetName();
				if (ClassName.empty()) continue;  // Skip if name is empty
			}
			catch (...)
			{
				continue;
			}
			
			// Filter: CharacterOutGame, CharacterBattle (including Chxxx), and NPCCitizen
			bool isCharacter = (ClassName == "CharacterOutGame" || ClassName == "ACharacterOutGame" ||
				ClassName == "CharacterBattle" || ClassName == "ACharacterBattle" ||
				ClassName == "SubCharacter");
			
			// Check for Ch001-Ch999 pattern (any Chxxx)
			bool isChxxx = false;
			if (ClassName.length() >= 5 && ClassName[0] == 'C' && ClassName[1] == 'h' &&
				std::isdigit(ClassName[2]) && std::isdigit(ClassName[3]) && std::isdigit(ClassName[4]))
			{
				isChxxx = true;
			}
			
			bool isNPC = (ClassName == "NPCCitizen");
			
			// Check for Items (23 item classes)
			bool isItem = (ClassName == "BP_Su001_C" ||  // HP Recovery Drink (Small)
						   ClassName == "BP_Su002_C" ||  // HP Recovery Drink (Large)
						   ClassName == "BP_Su003_C" ||  // Team HP Recovery Kit
						   ClassName == "BP_Su004_C" ||  // GP Recovery Drink (Small)
						   ClassName == "BP_Su005_C" ||  // GP Recovery Drink (Large)
						   ClassName == "BP_Su006_C" ||  // Team GP Recovery Kit
						   ClassName == "BP_Su007_C" ||  // Full Support Drink
						   ClassName == "BP_Su008_C" ||  // Item Bag (Small)
						   ClassName == "BP_Su009_C" ||  // Item Bag (Medium)
						   ClassName == "BP_Su010_C" ||  // Item Bag (Large)
						   ClassName == "BP_Su011_C" ||  // Level Up Card
						   ClassName == "BP_Su012_C" ||  // Item Box
						   ClassName == "BP_Su015_C" ||  // Team Enhancement Kit
						   ClassName == "BP_Su016_C" ||  // Item Box (Small)
						   ClassName == "BP_Su017_C" ||  // Item Box (Large)
						   ClassName == "BP_Su018_C" ||  // Item Box (Gold)
						   ClassName == "BP_Su020_C" ||  // Revive Card (1/3)
						   ClassName == "BP_Su021_C" ||  // Revive Card (Full)
						   ClassName == "BP_Su026_C" ||  // Team Support Drink
						   ClassName == "BP_AbilitySupplyAlpha_C" ||  // Ability Card (A)
						   ClassName == "BP_AbilitySupplyBeta_C" ||   // Ability Card (B)
						   ClassName == "BP_AbilitySupplyGamma_C");   // Ability Card (Y)
			
			if (!isCharacter && !isChxxx && !isNPC && !isItem)
				continue;
			
			// Cache this actor
			CachedActor cachedActor;
			cachedActor.ActorPtr = Actor;
			cachedActor.ClassName = ClassName;
			cachedActor.Position = Actor->K2_GetActorLocation();
			cachedActor.IsMySelf = SDK_GetCharacterOutGameIsMySelf(Actor);
			cachedActor.CitizenType = 0;
			
			// DETECT LOCAL PLAYER - Update cached team ID when we find ourselves
			if (cachedActor.IsMySelf && (ClassName == "CharacterBattle" || ClassName == "ACharacterBattle"))
			{
				uint8 myTeam = GetCharacterTeamId(Actor);
				if (myTeam != 255)  // Valid team ID
				{
					g_MyTeamId = myTeam;
					g_LastLocalPlayerCharacter = Actor;
				}
			}
			
			// Get character ID and costume (only for CharacterOutGame)
			if (ClassName == "CharacterOutGame" || ClassName == "ACharacterOutGame")
			{
				cachedActor.CharacterID = SDK_GetCharacterOutGameId(Actor);
				cachedActor.CostumeCode = SDK_GetCharacterOutGameCostumeCode(Actor);
				cachedActor.Health = 0.0f;
				cachedActor.MaxHealth = 0.0f;
				cachedActor.GuardPoint = 0.0f;
				cachedActor.MaxGuardPoint = 0.0f;
				cachedActor.TeamId = 255;
				cachedActor.IsBot = false;
				cachedActor.IsAlly = false;
			}
			else if (ClassName == "CharacterBattle" || ClassName == "ACharacterBattle")
			{
				cachedActor.CharacterID = 0;
				cachedActor.CostumeCode = -1;
				
				// Retrieve combat properties via SDK helpers
				cachedActor.Health = GetCharacterHealth(Actor);
				cachedActor.MaxHealth = GetCharacterMaxHealth(Actor);
				cachedActor.GuardPoint = GetCharacterGuardPoint(Actor);
				cachedActor.MaxGuardPoint = GetCharacterMaxGuardPoint(Actor);
				cachedActor.TeamId = GetCharacterTeamId(Actor);
				cachedActor.IsBot = IsCharacterBot(Actor);
				
				// Determine if ally (same team as me)
				cachedActor.IsAlly = IsAlly(cachedActor.TeamId);
			}
			else if (ClassName == "NPCCitizen")
			{
				cachedActor.CharacterID = 0;
				cachedActor.CostumeCode = -1;
				cachedActor.Health = 0.0f;
				cachedActor.MaxHealth = 0.0f;
				cachedActor.GuardPoint = 0.0f;
				cachedActor.MaxGuardPoint = 0.0f;
				cachedActor.TeamId = 255;
				cachedActor.IsBot = false;
				cachedActor.IsAlly = false;
				
				// Read NPC citizen type from SDK offset 0x0310 (ECitizenType)
				try
				{
					cachedActor.CitizenType = *(uint8*)(reinterpret_cast<uintptr_t>(Actor) + 0x0310);
				}
				catch (...)
				{
					cachedActor.CitizenType = 0;
				}
			}
			else
			{
				cachedActor.CharacterID = 0;
				cachedActor.CostumeCode = -1;
				cachedActor.Health = 0.0f;
				cachedActor.MaxHealth = 0.0f;
				cachedActor.GuardPoint = 0.0f;
				cachedActor.MaxGuardPoint = 0.0f;
				cachedActor.TeamId = 255;
				cachedActor.IsBot = false;
				cachedActor.IsAlly = false;
			}
			
			// SEPARATE ITEMS FROM ACTORS
			if (isItem)
			{
				newItemList.push_back(cachedActor);
			}
			else
			{
				newActorList.push_back(cachedActor);
			}
		}
		
		// Extract skeletons ONLY for CharacterOutGame, CharacterBattle, and ChXXX (not NPCs)
		int skeletonCount = 0;
		for (auto& cachedActor : newActorList)
		{
			// Filter: Only extract skeletons for playable characters, not NPCs
			bool shouldExtractSkeleton = (cachedActor.ClassName == "CharacterOutGame" || 
										   cachedActor.ClassName == "ACharacterOutGame" ||
										   cachedActor.ClassName == "CharacterBattle" || 
										   cachedActor.ClassName == "ACharacterBattle" ||
										   cachedActor.ClassName == "SubCharacter");
			
			// Check for Ch001-Ch999 pattern
			if (!shouldExtractSkeleton && cachedActor.ClassName.length() >= 5)
			{
				if (cachedActor.ClassName[0] == 'C' && cachedActor.ClassName[1] == 'h' &&
					std::isdigit(cachedActor.ClassName[2]) && std::isdigit(cachedActor.ClassName[3]) && 
					std::isdigit(cachedActor.ClassName[4]))
				{
					shouldExtractSkeleton = true;
				}
			}
			
			if (!shouldExtractSkeleton)
				continue;  // Skip NPCs - no skeleton extraction needed
			
			if (cachedActor.ActorPtr)
			{
				cachedActor.Skeleton = SDK_GetBones(cachedActor.ActorPtr);
				cachedActor.HasValidSkeleton = (cachedActor.Skeleton.Head.x > 0 && cachedActor.Skeleton.Head.y > 0);
				
				if (cachedActor.HasValidSkeleton)
				{
					skeletonCount++;
				}
			}
		}
		
		if (skeletonCount > 0)
		{
			// Debug logging removed for performance
		}
		
		// Swap buffers (thread-safe double-buffering like zero1's EntityList + EntityList2)
		{
			std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
			g_ActorsToProcess.swap(newActorList);
			g_ActorsForRendering.swap(g_ActorsToProcess);
		}
		
		// Swap item buffers separately
		{
			std::lock_guard<std::mutex> lock(g_ItemsCacheMutex);
			g_ItemsToProcess.swap(newItemList);
			g_ItemsForRendering.swap(g_ItemsToProcess);
		}
	}
	catch (...)
	{
		// Silently fail - will retry in 200ms
	}
}

/**
 * @brief Draw ESP boxes and labels from cached actors (OPTIMIZED - no enumeration per frame)
 */
static void SDK_DrawCachedActors()
{
	// Check if ESP is globally enabled
	if (!ImGuiMenu::g_Settings.EnablePlayerESP)
		return;
	
	// Lock briefly to copy the cached actor list
	std::vector<CachedActor> actorsToRender;
	{
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
		actorsToRender = g_ActorsForRendering;  // Copy (fast because not enumeration)
	}
	
	// Now process renders without holding lock (like zero1's pattern)
	for (const CachedActor& cachedActor : actorsToRender)
	{
		try
		{
			AActor* Actor = cachedActor.ActorPtr;
			
			// Verify actor still exists (safety check)
			if (!Actor || Actor->IsDefaultObject())
				continue;
			
			// Check if this is a ChXXX pattern (Ch001-Ch999)
			bool isChxxx = false;
			if (cachedActor.ClassName.length() >= 5)
			{
				if (cachedActor.ClassName[0] == 'C' && cachedActor.ClassName[1] == 'h' &&
					std::isdigit(cachedActor.ClassName[2]) && std::isdigit(cachedActor.ClassName[3]) && 
					std::isdigit(cachedActor.ClassName[4]))
				{
					isChxxx = true;
				}
			}
			
			// Filter by actor type based on menu settings
			if (cachedActor.ClassName == "CharacterOutGame" || cachedActor.ClassName == "ACharacterOutGame")
			{
				// This is a lobby character (out of game)
				if (!ImGuiMenu::g_Settings.ShowLobbyCharacters)
					continue;
			}
			else if (cachedActor.ClassName == "CharacterBattle" || cachedActor.ClassName == "ACharacterBattle" || isChxxx)
			{
				// This is a battle character (in game) - includes ChXXX patterns
			}
			
			// Filter by actor type based on menu settings
			if (cachedActor.ClassName == "CharacterOutGame" || cachedActor.ClassName == "ACharacterOutGame")
			{
				// This is a lobby character (out of game)
				if (!ImGuiMenu::g_Settings.ShowLobbyCharacters)
					continue;
			}
			else if (cachedActor.ClassName == "CharacterBattle" || cachedActor.ClassName == "ACharacterBattle" || isChxxx)
			{
				// This is a battle character (in game) - includes ChXXX patterns
				// Check what to show: enemies OR team (self + allies)
				bool isEnemyPlayer = !cachedActor.IsMySelf && !cachedActor.IsAlly;
				bool isTeamMember = cachedActor.IsMySelf || cachedActor.IsAlly;
				
				// Skip if neither ShowEnemies nor ShowTeam is enabled
				if (!ImGuiMenu::g_Settings.ShowEnemies && !ImGuiMenu::g_Settings.ShowTeam)
					continue;
				
				// If ShowEnemies is on, show enemies
				if (ImGuiMenu::g_Settings.ShowEnemies && isEnemyPlayer)
				{
					// Show enemies - continue rendering
				}
				// If ShowTeam is on, show team members
				else if (ImGuiMenu::g_Settings.ShowTeam && isTeamMember)
				{
					// Show team - continue rendering
				}
				// Otherwise skip this actor
				else
				{
					continue;
				}
			}
			else
			{
				// Not a character or battle actor - skip (e.g., NPCCitizen handled separately)
				continue;
			}
			
			// TEAM FILTERING: Skip if team ID doesn't match requirements
			// For now, show all teams (you can add UI toggles later for filtering by team)
			// Example: if (cachedActor.TeamId != 0) continue;  // Only show team 0
			
			// Skip bots if desired (can add UI toggle for this)
			// if (cachedActor.IsBot) continue;
			
			// Skip self if not enabled
			if (cachedActor.IsMySelf)
			{
				// You can add UI toggle: if (!showLocalPlayer) continue;
			}
			
			// Calculate distance (in UE4 cm units) and check max draw distance
			float distanceCm = SDK_GetDistanceToPosition(cachedActor.Position);
			float distanceMeters = distanceCm * 0.01f;  // Convert to meters for comparison/display
			
			if (distanceMeters > ImGuiMenu::g_Settings.Player_DrawDistance)
				continue;  // Skip actors beyond max draw distance
			
			// Project head and feet (like zero1)
			FVector HeadPos = cachedActor.Position;
			HeadPos.Z += 80.8f;
			
			FVector FeetPos = cachedActor.Position;
			FeetPos.Z -= 85.95f;
			
			FVector2D HeadScreenPos = { 0.0f, 0.0f };
			FVector2D FeetScreenPos = { 0.0f, 0.0f };
			
			bool HeadProjected = SDK_ProjectWorldToScreen(HeadPos, &HeadScreenPos);
			bool FeetProjected = SDK_ProjectWorldToScreen(FeetPos, &FeetScreenPos);
			
			if (!FeetProjected || !HeadProjected)
				continue;
			
			// Calculate box dimensions
			float projectedHeight = FeetScreenPos.Y - HeadScreenPos.Y;
			float boxWidth = (projectedHeight / 4.5f) * 1.3f;
			if (projectedHeight < 30.0f) projectedHeight = 30.0f;
			if (boxWidth < 20.0f) boxWidth = 20.0f;
			
			// Determine box color based on team and status
			ImU32 drawColor = ImGui::GetColorU32(ImVec4(1.0f, 0.0f, 0.0f, 1.0f));  // Red default (enemies)
			
			if (cachedActor.IsMySelf)
			{
				drawColor = ImGui::GetColorU32(ImVec4(0.0f, 1.0f, 0.0f, 1.0f));  // Green for self
			}
			else if (cachedActor.IsAlly)
			{
				drawColor = ImGui::GetColorU32(ImVec4(0.0f, 0.5f, 1.0f, 1.0f));  // Cyan for allies
			}
			else if (cachedActor.IsBot)
			{
				drawColor = ImGui::GetColorU32(ImVec4(1.0f, 1.0f, 0.0f, 1.0f));  // Yellow for enemy bots
			}
			// else: Red for enemy players (default)
			
			// Create rectangle adapted to skeleton (use all 22 bones for accurate bounding box)
			float minX = FLT_MAX;
			float maxX = FLT_MIN;
			float minY = FLT_MAX;
			float maxY = FLT_MIN;
			
			// Check all 22 skeleton bones to find true bounding box
			if (cachedActor.HasValidSkeleton)
			{
				const Bones& bones = cachedActor.Skeleton;
				
				// All 22 bones
				ImVec2 bonePositions[] = {
					bones.Head, bones.Neck, bones.Spine3, bones.Spine2, bones.Spine1, bones.Spine0,
					bones.LClavicle, bones.LUpperArm, bones.LForeArm, bones.LHand,
					bones.RClavicle, bones.RUpperArm, bones.RForeArm, bones.RHand,
					bones.LTight, bones.LCalf, bones.LFoot, bones.LToe,
					bones.RTight, bones.RCalf, bones.RFoot, bones.RToe
				};
				
				// Find min/max from all bone positions
				for (int i = 0; i < 22; i++)
				{
					if (bonePositions[i].x > 0.0f && bonePositions[i].y > 0.0f)  // Valid screen position
					{
						if (bonePositions[i].x < minX) minX = bonePositions[i].x;
						if (bonePositions[i].x > maxX) maxX = bonePositions[i].x;
						if (bonePositions[i].y < minY) minY = bonePositions[i].y;
						if (bonePositions[i].y > maxY) maxY = bonePositions[i].y;
					}
				}
				
				// If all bones are invalid, fallback to FLT_MAX init
				if (minX == FLT_MAX || maxX == FLT_MIN)
				{
					minX = FeetScreenPos.X - boxWidth;
					maxX = FeetScreenPos.X + boxWidth;
					minY = FeetScreenPos.Y;
					maxY = HeadScreenPos.Y;
				}
				else
				{
					// Add small padding to the bounding box
					float paddingX = (maxX - minX) * 0.05f;
					float paddingY = (maxY - minY) * 0.05f;
					minX -= paddingX;
					maxX += paddingX;
					minY -= paddingY;
					maxY += paddingY;
					
					// Ensure min < max (swap if inverted)
					if (minX > maxX) std::swap(minX, maxX);
					if (minY > maxY) std::swap(minY, maxY);
				}
			}
			else
			{
				// Fallback: use old method if skeleton not valid
				minX = FeetScreenPos.X - boxWidth;
				maxX = FeetScreenPos.X + boxWidth;
				minY = FeetScreenPos.Y;
				maxY = HeadScreenPos.Y;
			}
			
			// Distance already calculated for max draw distance check above
			
			// Queue rectangle
			Rect2D rect;
			rect.minX = minX;
			rect.minY = minY;
			rect.maxX = maxX;
			rect.maxY = maxY;
			rect.color = drawColor;
			rect.distance = distanceCm;  // Keep in UE4 cm for font sizing (like zero1)
			rect.health = cachedActor.Health;
			rect.maxHealth = cachedActor.MaxHealth;
			rect.guardPoint = cachedActor.GuardPoint;
			rect.maxGuardPoint = cachedActor.MaxGuardPoint;
			rect.plusUltra = GetCharacterPlusUltra(Actor);
			rect.maxPlusUltra = rect.plusUltra > 0.0f ? 100.0f : 0.0f;  // Assume max 100 for PU
			rect.isDying = GetCharacterIsDying(Actor);
			rect.platform = GetCharacterPlatform(Actor);
			
			{
				std::lock_guard<std::mutex> lock(g_RectMutex);
				if (g_RectsToDraw.size() < MAX_ESP_BOXES)
					g_RectsToDraw.push_back(rect);
			}
			
			// Queue actor name text with team ID and health info
			try
			{
				const char* playerName = SDK_GetActorDisplayName(Actor, cachedActor.IsMySelf, false);
				std::string displayText = playerName ? playerName : "Unknown";
				
				// Add platform if enabled
				if (ImGuiMenu::g_Settings.ShowPlatform)
				{
					uint8 platform = GetCharacterPlatform(Actor);
					const char* platformStr;
					switch (platform) {
						case 1: platformStr = " PS"; break;
						case 2: platformStr = " XB"; break;
						case 3: platformStr = " PC"; break;
						case 4: platformStr = " SW"; break;
						default: platformStr = ""; break;
					}
					displayText += platformStr;
				}
				
// Add team ID if valid and enabled
			if (ImGuiMenu::g_Settings.ShowTeamId && cachedActor.TeamId < 255)
				{
					displayText += " T" + std::to_string(cachedActor.TeamId) + "";
				}
				
				// Add ally/bot indicator
				if (cachedActor.IsAlly && !cachedActor.IsMySelf)
				{
					displayText += " Me";
				}
				else if (cachedActor.IsBot)
				{
					displayText += " [BOT]";
				}
				
				if (!displayText.empty())
				{
					TextLabel label;
					label.x = (minX + maxX) / 2.0f;  // Center horizontally on adaptive box
					label.y = minY - 10.0f;         // Above the box top
					label.distance = distanceCm;  // Distance in UE4 cm for font sizing formula (like zero1)
					label.color = drawColor;
					label.text = displayText;
					
					{
						std::lock_guard<std::mutex> lock(g_TextMutex);
						if (g_TextToDraw.size() < MAX_ESP_BOXES)
							g_TextToDraw.push_back(label);
					}
				}
			}
			catch (...)
			{
				// Silently ignore name errors
			}
		}
		catch (...)
		{
			// Silently ignore draw errors
		}
	}
	
	// ===== NPC/KOTA RENDERING (NO BOXES, JUST TEXT) =====
	// Draw NPCCitizen actors with special handling
	for (const CachedActor& cachedActor : actorsToRender)
	{
		try
		{
			// Only process NPCCitizen
			if (cachedActor.ClassName != "NPCCitizen")
				continue;
			
			// Only show if SPECIAL_KID (citizenType == 4)
			if (cachedActor.CitizenType != 4)
				continue;
			
			// Skip if KOTA display disabled
			if (!ImGuiMenu::g_Settings.ShowKota)
				continue;
			
			AActor* Actor = cachedActor.ActorPtr;
			if (!Actor || Actor->IsDefaultObject())
				continue;
			
			// Calculate distance (in UE4 cm units, no filtering for KOTA)
			float distanceCm = SDK_GetDistanceToPosition(cachedActor.Position);
			float distanceMeters = distanceCm * 0.01f;  // Convert to meters for display only
			
			// Project to screen
			FVector2D screenPos = { 0.0f, 0.0f };
			if (!SDK_ProjectWorldToScreen(cachedActor.Position, &screenPos))
				continue;
			
			// Create text label for KOTA
			try
			{
				std::string displayText = "KOTA";
				
				// Add distance
				char distStr[32];
				snprintf(distStr, sizeof(distStr), " [%.1fm]", distanceMeters);  // Display in meters
				displayText += distStr;
				
				if (!displayText.empty())
				{
					TextLabel label;
					label.x = screenPos.X;
					label.y = screenPos.Y;
					label.distance = distanceCm;  // Distance in UE4 cm (not used with isFixedSize)
					label.color = IM_COL32(200, 100, 200, 255);  // Magenta for NPCs
					label.text = displayText;
					label.isFixedSize = true;  // Fixed size - always visible
					
					{
						std::lock_guard<std::mutex> lock(g_TextMutex);
						if (g_TextToDraw.size() < MAX_ESP_BOXES)
							g_TextToDraw.push_back(label);
					}
				}
			}
			catch (...)
			{
				// Silently ignore NPC label errors
			}
		}
		catch (...)
		{
			// Silently ignore NPC draw errors
		}
	}
}

