/**
 * @brief Main aimbot tick function
 */
extern "C" void SDK_RunAimbot()
{
	// Check if aimbot enabled from menu
	if (!ImGuiMenu::g_Settings.EnableAimbot)
		return;
		
	// Zero1 exact: Don't aim when game is active (menu focused)
	if (IsGameActive() == false)  // If game is NOT focused
		return;
	
	// Don't test gamepad hotkey when menu is open (avoid interference)
	bool menuVisible = ImGuiMenu::IsVisible();
	
	// Zero1 EXACT: Check hotkey input (exactly as Zero1 does)
	bool keyboardPressed = IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.Keyboard, HotKeyType::KeyboardMouse);
	bool gamepadPressed = false;
	
	// Only test gamepad hotkey when menu is NOT visible
	if (!menuVisible)
	{
		gamepadPressed = IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.Xbox, HotKeyType::Gamepad) ||
	                   IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.PS4, HotKeyType::Gamepad);
	}
	
	bool hotKeyPressed = keyboardPressed || gamepadPressed;
	
	// If hotkey is NOT pressed, clear sticky target and return
	if (!hotKeyPressed)
	{
		g_LastAimbotTargetPtr = nullptr;  // Reset sticky target when hotkey released
		return;
	}
	
	// Get player controller
	APlayerController* playerController = SDK_GetPlayerController();
	if (!playerController)
		return;
	
	// Get camera location
	FVector cameraPos = SDK_GetCameraLocation();
	if (cameraPos.X == 0 && cameraPos.Y == 0 && cameraPos.Z == 0)
		return;
	
	// Select target (only when hotkey is held)
	AimbotTarget target = SelectAimbotTarget();
	if (!target.isValid)
		return;
	
	// ZERO1 VALIDATION: Ensure target still exists in actor list (double-check for safety)
	// Like Zero1: "if (!Structures.EntityList2.Contains(currentTarget_Aimbot)) currentTarget_Aimbot = null;"
	{
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
		bool targetStillValid = false;
		for (auto& actor : g_ActorsForRendering)
		{
			if (&actor == target.actor)
			{
				targetStillValid = true;
				break;
			}
		}
		if (!targetStillValid)
		{
			g_LastAimbotTargetPtr = nullptr;
			return;  // Target disappeared, abort aiming
		}
	}
	
	// DON'T read from controller (includes player movement artifacts)
	// Use last applied rotation instead for smooth interpolation
	// (this prevents drift when player moves)
	
	// Get target bone world position (exact 3D position from skeleton)
	if (!target.actor || !target.actor->ActorPtr)
		return;
	
	// ANTI-CHEAT SAFETY: Validate target state before aiming (exactly like Zero1)
	// Skip if target became downed since selection
	if (IsCharacterDowned(target.actor->ActorPtr))
		return;
	
	// Skip if target became ally since selection (safety check)
	if (target.actor->IsAlly)
		return;
	
	// Get exact 3D bone positions using our skeleton extraction (EXACTLY LIKE ZERO1)
	std::vector<FVector> bonePositions = SDK_GetBonePositions(target.actor->ActorPtr);
	if (bonePositions.empty() || bonePositions.size() < 5)
		return;
	
	// Use Head bone position (index 4) for accurate aiming
	FVector targetWorldPos = bonePositions[4];  // bonePositions[4] = Head
	
	// Fallback if head position is invalid
	if (targetWorldPos.X == 0 && targetWorldPos.Y == 0 && targetWorldPos.Z == 0)
	{
		targetWorldPos = target.actor->Position;
		targetWorldPos.Z += 150.0f;  // Fallback offset
	}
	
	// Get target velocity for prediction
	FVector targetVelocity = target.actor->ActorPtr->GetVelocity();
	
	// Get local player velocity (Zero1 exact: MyMovement - player's own velocity)
	// Use playerController's pawn/character to get local player velocity
	FVector localPlayerVelocity = FVector(0, 0, 0);
	if (playerController && playerController->Pawn)
	{
		localPlayerVelocity = playerController->Pawn->GetVelocity();
	}
	
	// Calculate distance and time-to-bullet (INTERNAL: use real-time positions, not velocity-adjusted)
	// We have exact positions in real-time, unlike external which must predict
	FVector deltaPos = targetWorldPos - cameraPos;
	float distance = sqrtf(deltaPos.X * deltaPos.X + deltaPos.Y * deltaPos.Y + deltaPos.Z * deltaPos.Z);
	float timeToBullet = (distance > 0.001f) ? (distance / 100.0f) : 0.001f;  // Avoid division by zero
	
	// Zero1 exact: Per-character bullet speeds (18k-25k UU/s typical)
	// Read actual CharacterID and Variant from the target actor
	if (!target.actor->ActorPtr || target.actor->ActorPtr->IsDefaultObject())
	{
		Logger::LogWarning("[Aimbot] ERROR: Target actor pointer became invalid");
		g_LastAimbotTargetPtr = nullptr;
		return;
	}
	
	uint8_t charID = *(uint8_t*)(target.actor->ActorPtr + 0x0368);
	uint8_t variant = *(uint8_t*)(target.actor->ActorPtr + 0x0377);
	UHeroProjectileMovementComponent bulletSpeedComponent = GetBulletSpeed(charID, variant);
	float bulletSpeed = bulletSpeedComponent.InitialSpeed;
	if (bulletSpeed < 100.0f) bulletSpeed = 1000.0f;  // Safety fallback
	
	// Determine prediction method (check menu settings - default: disabled for now)
	bool usePrediction = ImGuiMenu::g_Settings.AimbotSmoothing;  // Use as proxy for now
	int predictionMethod = 0;  // Default: Method 0
	
	FVector aimAngles;
	
	if (!usePrediction || targetVelocity.X == 0 && targetVelocity.Y == 0 && targetVelocity.Z == 0)
	{
		// NO PREDICTION: Simple aim at current position (Method 0 without velocity)
		aimAngles = CalculateAimAngles_Method0(cameraPos, targetWorldPos);
	}
	else if (predictionMethod == 0)
	{
		// METHOD 0: Simple velocity prediction (Zero1 exact)
		// headBone_Aimbot += currentTarget_Aimbot.Velocity / timeToBullet;
		FVector predictedPos = targetWorldPos;
		if (timeToBullet > 0.001f)
		{
			predictedPos += targetVelocity / timeToBullet;
		}
		aimAngles = CalculateAimAngles_Method0(cameraPos, predictedPos);
	}
	else
	{
		// METHOD 1: Ballistic prediction with gravity (Zero1 exact)
		// Use actual character's ProjectileGravityScale from bulletSpeedComponent (NOT multiplied by 980)
		float gravityScale = bulletSpeedComponent.ProjectileGravityScale;
		if (gravityScale <= 0.0f) gravityScale = 0.5f;  // Fallback default
		aimAngles = CalculateAimAngles_Method1(cameraPos, targetWorldPos, targetVelocity, 
			gravityScale, bulletSpeed);
	}
	
	// Apply smoothing if enabled (exactly like Zero1)
	float smoothFactorH = ImGuiMenu::g_Settings.AimbotSmoothFactor;  // Use menu setting (Horizontal/Yaw)
	float smoothFactorV = ImGuiMenu::g_Settings.AimbotSmoothFactor;  // Use menu setting (Vertical/Pitch)
	
	// Clamping smoothing values like Zero1 (max 0.4)
	if (smoothFactorH >= 0.45f) smoothFactorH = 0.4f;
	if (smoothFactorV >= 0.45f) smoothFactorV = 0.4f;
	
	if (ImGuiMenu::g_Settings.AimbotSmoothing)
	{
		// Smooth from LAST APPLIED rotation, not controller (prevents drift)
		aimAngles.X = SmoothDampAngle(g_LastAppliedAimAngles.Pitch, aimAngles.X, smoothFactorV);
		aimAngles.Y = SmoothDampAngle(g_LastAppliedAimAngles.Yaw, aimAngles.Y, smoothFactorH);
	}
	
	// Clamp pitch
	if (aimAngles.X > 89.0f) aimAngles.X = 89.0f;
	if (aimAngles.X < -89.0f) aimAngles.X = -89.0f;
	
	// Write to ControlRotation offset (0x288 = 648 decimal)
	// Write 25 times for stability - Zero1 exact match
	uintptr_t controlRotationAddr = (uintptr_t)playerController + 0x288;
	for (int i = 0; i < 25; i++)
	{
		try
		{
			*(FVector*)(controlRotationAddr) = aimAngles;
		}
		catch (...)
		{
			// Skip write errors
		}
	}
	
	// Track what we just applied (for smooth damping next frame)
	g_LastAppliedAimAngles = FRotator(aimAngles.X, aimAngles.Y, 0);
	
	// Update last target time
	g_LastAimbotTargetTime = GetCurrentTimeMs();
}

/**
 * @brief Check if bullet name matches Alpha skill patterns (like Zero1)
 * Alpha skills: Unique1, CementShot, Cracker, FogShot, etc.
 */
static bool IsAlphaSkillBullet(const std::string& bulletName)
{
	if (bulletName.empty())
		return false;
	
	// Alpha patterns from Zero1 analysis
	const char* alphaPatterns[] = {
		"Unique1",           // Generic Alpha marker
		"BPB_CementShot",    // Cement skill
		"BPB_Cement_L",      // Cement variant
		"BPB_Cracks_L",      // Cracker skill
		"BPB_FogShot_",      // Fog skill
		"BPB202_U1_",        // Character-specific Alpha
		nullptr
	};
	
	// Check if any pattern matches
	for (int i = 0; alphaPatterns[i] != nullptr; i++)
	{
		if (bulletName.find(alphaPatterns[i]) != std::string::npos)
			return true;
	}
	
	return false;
}

/**
 * @brief Get class name from UObject (usually at offset 0x18 or via VTable)
 * Simplified: reads class name for bullet type identification
 */
static std::string GetActorClassName(AActor* actor)
{
	if (!actor || !IsValidAddress((uintptr_t)actor))
		return "";
	
	try
	{
		// Get class pointer (at offset 0 in UObject)
		uintptr_t classPtr = *(uintptr_t*)actor;
		if (!IsValidAddress(classPtr))
			return "";
		
		// Get class name from class object (offset 0x18 for FName)
		uintptr_t classNameAddr = classPtr + 0x18;
		char nameBuffer[256] = {0};
		
		// Try to read name
		memcpy(nameBuffer, (void*)classNameAddr, sizeof(nameBuffer) - 1);
		
		return std::string(nameBuffer);
	}
	catch (...)
	{
		return "";
	}
}

/**
 * @brief Silent Aim (Bullet TP) for Alpha Skills - teleports bullets to target
 * Uses Zero1's direct bullet position teleportation technique with Alpha filtering
 */
extern "C" void SDK_RunSilentAim()
{
	// Check if bullet tp enabled
	if (!ImGuiMenu::g_Settings.EnableBulletTP)
		return;
	
	if (IsGameActive() == false)
		return;
	
	bool menuVisible = ImGuiMenu::IsVisible();
	
	// Check hotkey input (uses Aimbot hotkeys)
	bool keyboardPressed = IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.Keyboard, HotKeyType::KeyboardMouse);
	bool gamepadPressed = false;
	
	if (!menuVisible)
	{
		gamepadPressed = IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.Xbox, HotKeyType::Gamepad) ||
						IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.PS4, HotKeyType::Gamepad);
	}
	
	bool flag = keyboardPressed || gamepadPressed;
	if (!flag)
		return;
	
	Logger::LogInfo("[BulletTP] ===== BULLETTP TICK START =====");
	BulletTPLog("===== BULLETTP TICK START =====");
	
	// Get player controller
	APlayerController* playerController = SDK_GetPlayerController();
	if (!playerController || !playerController->Pawn)
	{
		Logger::LogWarning("[BulletTP] ERROR: No player controller or pawn");
		BulletTPLog("ERROR: No player controller or pawn");
		return;
	}
	
	// Get player pawn (for bullet enumeration)
	ACharacter* playerPawn = (ACharacter*)playerController->Pawn;
	
	// Enumerate bullets from player (OwningBullets TArray at offset 2512 - like Zero1)
	std::vector<AActor*> bullets = GetOwningBullets(playerPawn);
	
	char logMsg[256];
	snprintf(logMsg, sizeof(logMsg), "[BulletTP] Found %d bullets from player", (int)bullets.size());
	Logger::LogInfo(logMsg);
	BulletTPLog("Found %d bullets from player", (int)bullets.size());
	
	if (bullets.empty())
	{
		Logger::LogInfo("[BulletTP] No bullets found - returning");
		BulletTPLog("No bullets found - returning");
		return;
	}
	
	// Get camera location for target selection
	FVector cameraPos = SDK_GetCameraLocation();
	if (cameraPos.X == 0 && cameraPos.Y == 0 && cameraPos.Z == 0)
	{
		Logger::LogWarning("[BulletTP] ERROR: Invalid camera position");
		BulletTPLog("ERROR: Invalid camera position");
		return;
	}
	
	char camLog[256];
	snprintf(camLog, sizeof(camLog), "[BulletTP] Camera pos: (%.1f, %.1f, %.1f)", cameraPos.X, cameraPos.Y, cameraPos.Z);
	Logger::LogInfo(camLog);
	BulletTPLog("Camera pos: (%.1f, %.1f, %.1f)", cameraPos.X, cameraPos.Y, cameraPos.Z);
	
	// Select target using Silent Aim FOV settings
	AimbotTarget target = SelectSilentAimTarget();
	if (!target.isValid)
	{
		Logger::LogWarning("[BulletTP] ERROR: No valid target found in FOV");
		BulletTPLog("ERROR: No valid target found in FOV");
		return;
	}
	
	char targetLog[256];
	snprintf(targetLog, sizeof(targetLog), "[BulletTP] Target found: %s", 
		target.actor ? target.actor->ClassName.c_str() : "NULL");
	Logger::LogInfo(targetLog);
	BulletTPLog("Target found: %s", target.actor ? target.actor->ClassName.c_str() : "NULL");
	
	// Validate target still exists
	{
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
		bool targetStillValid = false;
		for (auto& actor : g_ActorsForRendering)
		{
			if (&actor == target.actor)
			{
				targetStillValid = true;
				break;
			}
		}
		if (!targetStillValid)
		{
			Logger::LogWarning("[BulletTP] ERROR: Target no longer in actor cache");
			BulletTPLog("ERROR: Target no longer in actor cache");
			g_LastSilentAimTargetPtr = nullptr;
			return;
		}
	}
	
	// Validate target state
	if (IsCharacterDowned(target.actor->ActorPtr))
	{
		Logger::LogWarning("[BulletTP] ERROR: Target is downed");
		BulletTPLog("ERROR: Target is downed");
		return;
	}
	
	if (target.actor->IsAlly)
	{
		Logger::LogWarning("[BulletTP] ERROR: Target is ally");
		BulletTPLog("ERROR: Target is ally");
		return;
	}
	
	// Get bone positions in world coordinates (NOT screen coordinates)
	std::vector<FVector> bonePositions = SDK_GetBonePositions(target.actor->ActorPtr);
	if (bonePositions.empty() || bonePositions.size() < 5)
	{
		char boneLog[256];
		snprintf(boneLog, sizeof(boneLog), "[BulletTP] ERROR: Invalid bone positions (size: %d)", (int)bonePositions.size());
		Logger::LogWarning(boneLog);
		BulletTPLog("ERROR: Invalid bone positions (size: %d)", (int)bonePositions.size());
		return;
	}
	
	char bonePosLog[256];
	snprintf(bonePosLog, sizeof(bonePosLog), "[BulletTP] Got %d bone positions", (int)bonePositions.size());
	Logger::LogInfo(bonePosLog);
	BulletTPLog("Got %d bone positions", (int)bonePositions.size());
	
	// Always aim at Head (index 0) for BulletTP
	int boneIndex = 0;  // Head bone
	
	FVector targetBonePos = GetBoneByIndex(bonePositions, boneIndex);
	
	// Fallback if bone position is invalid
	if (targetBonePos.X == 0 && targetBonePos.Y == 0 && targetBonePos.Z == 0)
	{
		targetBonePos = target.actor->Position;
		targetBonePos.Z += 150.0f;  // Approximate head height
		Logger::LogWarning("[BulletTP] Using fallback head position (invalid bone)");
		BulletTPLog("Using fallback head position (invalid bone)");
	}
	
	char headLog[256];
	snprintf(headLog, sizeof(headLog), "[BulletTP] Target head bone pos: (%.1f, %.1f, %.1f)", 
		targetBonePos.X, targetBonePos.Y, targetBonePos.Z);
	Logger::LogInfo(headLog);
	BulletTPLog("Target head bone pos: (%.1f, %.1f, %.1f)", targetBonePos.X, targetBonePos.Y, targetBonePos.Z);
	
	// Process each bullet - TELEPORT TO TARGET (like Zero1)
	static std::vector<AActor*> processedBullets;  // Track which bullets we've processed this frame
	
	int bulletsProcessed = 0;
	int bulletsIgnored = 0;
	
	char procLog[256];
	snprintf(procLog, sizeof(procLog), "[BulletTP] Processing %d bullets...", (int)bullets.size());
	Logger::LogInfo(procLog);
	BulletTPLog("Processing %d bullets...", (int)bullets.size());
	
	for (AActor* bullet : bullets)
	{
		if (!bullet)
		{
			Logger::LogDebug("[BulletTP]   - NULL bullet, skipping");
			BulletTPLog("  - NULL bullet, skipping");
			continue;
		}
		
		// Skip if already processed this frame
		bool alreadyProcessed = false;
		for (AActor* processed : processedBullets)
		{
			if (processed == bullet)
			{
				alreadyProcessed = true;
				break;
			}
		}
		if (alreadyProcessed)
		{
			BulletTPLog("  - Bullet already processed this frame, skipping");
			continue;
		}
		
		try
		{
			// Get bullet class name
			std::string bulletClassName = GetActorClassName(bullet);
			
			char tpLog[256];
			snprintf(tpLog, sizeof(tpLog), "[BulletTP]   - Bullet '%s' TELEPORTING", bulletClassName.c_str());
			Logger::LogInfo(tpLog);
			BulletTPLog("  - Bullet '%s' TELEPORTING", bulletClassName.c_str());
			
			// Teleport bullet to target bone position 25 times (like Zero1)
			// Offset 464 = USphereComponent.unk_TeleportOff (bullet position)
			TeleportBulletToPosition(bullet, targetBonePos);
			
			// Mark as processed
			processedBullets.push_back(bullet);
			bulletsProcessed++;
		}
		catch (...)
		{
			BulletTPLog("  - Exception caught while processing bullet");
			continue;
		}
	}
	
	char summaryLog[256];
	snprintf(summaryLog, sizeof(summaryLog), "[BulletTP] Summary: %d processed, %d ignored", bulletsProcessed, bulletsIgnored);
	Logger::LogInfo(summaryLog);
	BulletTPLog("Summary: %d processed, %d ignored", bulletsProcessed, bulletsIgnored);
	
	// Clear processed bullets after a short delay
	static int frameCounter = 0;
	frameCounter++;
	if (frameCounter > 5)  // 5 frames = ~83ms at 60 FPS
	{
		processedBullets.clear();
		frameCounter = 0;
	}
	
	Logger::LogInfo("[BulletTP] ===== BULLETTP TICK END =====");
	BulletTPLog("===== BULLETTP TICK END =====");
}

/**
 * @brief Draw aimbot visualization (crosshair on target)
 */
/**
 * @brief Draw aimbot FOV circle on screen
 */
extern "C" void SDK_DrawAimbotFOV()
{
	ImDrawList* drawlist = ImGui::GetForegroundDrawList();
	if (!drawlist)
		return;

	// Only draw if aimbot enabled and setting is on
	if (!ImGuiMenu::g_Settings.EnableAimbot || !ImGuiMenu::g_Settings.AimbotDrawFOV)
		return;

	// Get viewport size
	int32 vX = 0, vY = 0;
	SDK_GetViewportSize(&vX, &vY);
	if (vX <= 0 || vY <= 0)
		return;

	float screenCenterX = (float)vX / 2.0f;
	float screenCenterY = (float)vY / 2.0f;

	// FOV circle radius (from menu setting)
	float fovRadius = ImGuiMenu::g_Settings.AimbotFOVRadius;

	// Draw circle: yellow outline, semi-transparent
	ImU32 fovColor = IM_COL32(255, 255, 0, 100);  // Yellow, semi-transparent
	drawlist->AddCircle(
		ImVec2(screenCenterX, screenCenterY),
		fovRadius,
		fovColor,
		64,  // Number of segments for smooth circle
		2.0f  // Line thickness
	);
}

extern "C" void SDK_DrawAimbotInfo()
{
	if (!ImGuiMenu::g_Settings.EnableAimbot || !ImGuiMenu::g_Settings.AimbotDrawLine)
		return;
	
	// Get viewport size ONCE before the loop (expensive operation)
	int32 vpX = 0, vpY = 0;
	SDK_GetViewportSize(&vpX, &vpY);
	ImVec2 centerScreen(vpX / 2.0f, vpY / 2.0f);
	
	std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
	for (const auto& cachedActor : g_ActorsForRendering)
	{
		if (!cachedActor.HasValidSkeleton || cachedActor.IsMySelf)
			continue;
		
		ImVec2 headPos = cachedActor.Skeleton.Head;
		if (headPos.x <= 0 || headPos.y <= 0)
			continue;
		
		ImDrawList* drawlist = ImGui::GetForegroundDrawList();
		if (!drawlist)
			continue;
		
		// Draw a small circle on the target head
		drawlist->AddCircle(headPos, 5.0f, IM_COL32(255, 255, 0, 255), 0, 2.0f);
		
		// Draw line from center to head
		drawlist->AddLine(centerScreen, headPos, IM_COL32(255, 255, 0, 200), 1.5f);
	}
}

/**
 * @brief Log TeleportToKota debug info to file
 */
static inline void TeleportToKotaLog(const char* format, ...)
{
	try
	{
		va_list args;
		va_start(args, format);
		
		// Format message
		char buffer[512];
		vsnprintf(buffer, sizeof(buffer), format, args);
		va_end(args);
		
		// Write to file C:\temp\TeleportToKota_Debug.log
		static std::ofstream logFile;
		if (!logFile.is_open())
		{
			logFile.open("C:\\temp\\TeleportToKota_Debug.log", std::ios::app);
		}
		
		if (logFile.is_open())
		{
			logFile << buffer << "\n";
			logFile.flush();
		}
	}
	catch (...)
	{
		// Silently fail if file write fails
	}
}

/**
 * @brief Teleport to Kota (special NPC) with definable hotkey
 */
extern "C" void SDK_RunTeleportToKota()
{
	// Check if teleport enabled
	if (!ImGuiMenu::g_Settings.EnableTeleportToKota)
	{
		// Log only occasionally to avoid spam
		static int frameCounter = 0;
		frameCounter++;
		if (frameCounter > 300)  // Every 5 seconds at 60 FPS
		{
			TeleportToKotaLog("[DISABLED] TeleportToKota feature is disabled");
			frameCounter = 0;
		}
		return;
	}
	
	TeleportToKotaLog("===== TELEPORT TO KOTA TICK START =====");
	
	// Note: We DON'T check IsGameActive() here because we want to teleport even with menu open
	// (Unlike aimbot which needs to be disabled when menu is visible)
	
	bool menuVisible = ImGuiMenu::IsVisible();
	
	// Check hotkey input (Keyboard/Mouse + Gamepad)
	bool keyboardPressed = IsKeyPressed(ImGuiMenu::g_Settings.TeleportToKotaKey.Keyboard, HotKeyType::KeyboardMouse);
	bool gamepadPressed = false;
	
	if (!menuVisible)
	{
		gamepadPressed = IsKeyPressed(ImGuiMenu::g_Settings.TeleportToKotaKey.Xbox, HotKeyType::Gamepad) ||
						IsKeyPressed(ImGuiMenu::g_Settings.TeleportToKotaKey.PS4, HotKeyType::Gamepad);
	}
	
	TeleportToKotaLog("[Hotkey Check] Keyboard: %s, Gamepad: %s", 
		keyboardPressed ? "PRESSED" : "not pressed", 
		gamepadPressed ? "PRESSED" : "not pressed");
	
	bool hotKeyPressed = keyboardPressed || gamepadPressed;
	if (!hotKeyPressed)
	{
		TeleportToKotaLog("Hotkey NOT pressed - skipping");
		return;  // Hotkey not pressed
	}
	
	TeleportToKotaLog("✓ Hotkey detected!");
	
	// Get player controller
	APlayerController* playerController = SDK_GetPlayerController();
	if (!playerController)
	{
		TeleportToKotaLog("ERROR: PlayerController is NULL");
		Logger::LogWarning("[TeleportToKota] ERROR: No player controller");
		return;
	}
	
	if (!playerController->Pawn)
	{
		TeleportToKotaLog("ERROR: PlayerController->Pawn is NULL");
		Logger::LogWarning("[TeleportToKota] ERROR: No player pawn");
		return;
	}
	
	TeleportToKotaLog("✓ PlayerController and Pawn valid");
	
	// Find Kota in actor cache (NPCCitizen with CitizenType == 4)
	CachedActor* kotaActor = nullptr;
	int actorCount = 0;
	{
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
		
		TeleportToKotaLog("Searching through %d actors in cache for NPCCitizen (CitizenType=4)...", (int)g_ActorsForRendering.size());
		actorCount = g_ActorsForRendering.size();
		
		for (auto& actor : g_ActorsForRendering)
		{
			if (!actor.ActorPtr)
			{
				TeleportToKotaLog("  Skipping: ActorPtr is NULL");
				continue;
			}
			
			TeleportToKotaLog("  Checking actor: %s | CitizenType: %d (IsMySelf:%d)", 
				actor.ClassName.c_str(), (int)actor.CitizenType, actor.IsMySelf ? 1 : 0);
			
			// Search for NPCCitizen with CitizenType == 4 (SPECIAL_KID)
			if (actor.ClassName == "NPCCitizen" && actor.CitizenType == 4 && !actor.IsMySelf)
			{
				TeleportToKotaLog("  → Found SPECIAL_KID: NPCCitizen (CitizenType=4) ✓");
				kotaActor = &actor;
				TeleportToKotaLog("✓ KOTA FOUND - NPCCitizen SPECIAL_KID selected");
				break;
			}
		}
	}
	
	if (!kotaActor)
	{
		TeleportToKotaLog("ERROR: SPECIAL_KID NOT found in %d actors", actorCount);
		Logger::LogWarning("[TeleportToKota] ERROR: SPECIAL_KID (NPCCitizen CitizenType=4) not found in actor cache");
		TeleportToKotaLog("===== TELEPORT TO KOTA TICK END (FAILED - SPECIAL_KID NOT FOUND) =====");
		return;
	}
	
	// Get Kota's position
	FVector kotaPosition = kotaActor->Position;
	TeleportToKotaLog("Kota Position (raw): X=%.1f, Y=%.1f, Z=%.1f", kotaPosition.X, kotaPosition.Y, kotaPosition.Z);
	
	if (kotaPosition.X == 0 && kotaPosition.Y == 0 && kotaPosition.Z == 0)
	{
		TeleportToKotaLog("ERROR: Kota position is all zeros (invalid)");
		Logger::LogWarning("[TeleportToKota] ERROR: Invalid Kota position");
		TeleportToKotaLog("===== TELEPORT TO KOTA TICK END (FAILED - INVALID POS) =====");
		return;
	}
	
	// Offset height to spawn above ground (avoid stuck)
	kotaPosition.Z += 100.0f;
	TeleportToKotaLog("Kota Position (adjusted +100cm): X=%.1f, Y=%.1f, Z=%.1f", kotaPosition.X, kotaPosition.Y, kotaPosition.Z);
	
	// Get player pawn
	AActor* playerPawn = playerController->Pawn;
	if (!playerPawn)
	{
		TeleportToKotaLog("ERROR: Player pawn is NULL");
		Logger::LogWarning("[TeleportToKota] ERROR: Player pawn is null");
		TeleportToKotaLog("===== TELEPORT TO KOTA TICK END (FAILED - NULL PAWN) =====");
		return;
	}
	
	TeleportToKotaLog("✓ Player pawn valid - calling K2_TeleportTo...");
	
	// Teleport player to Kota using K2_TeleportTo
	FRotator dummyRotation = FRotator(0, 0, 0);  // Keep current rotation
	bool teleportSuccess = playerPawn->K2_TeleportTo(kotaPosition, dummyRotation);
	
	if (teleportSuccess)
	{
		char logMsg[256];
		snprintf(logMsg, sizeof(logMsg), "[TeleportToKota] SUCCESS: Teleported to Kota at (%.1f, %.1f, %.1f)", 
			kotaPosition.X, kotaPosition.Y, kotaPosition.Z);
		Logger::LogInfo(logMsg);
		
		TeleportToKotaLog("✓✓✓ SUCCESS ✓✓✓");
		TeleportToKotaLog("Teleported to Kota at (%.1f, %.1f, %.1f)", kotaPosition.X, kotaPosition.Y, kotaPosition.Z);
		TeleportToKotaLog("===== TELEPORT TO KOTA TICK END (SUCCESS) =====");
	}
	else
	{
		Logger::LogWarning("[TeleportToKota] ERROR: Teleport failed");
		TeleportToKotaLog("✗✗✗ FAILED ✗✗✗");
		TeleportToKotaLog("K2_TeleportTo() returned FALSE - teleport failed");
		TeleportToKotaLog("===== TELEPORT TO KOTA TICK END (FAILED - K2_TELEPORTTO RETURNED FALSE) =====");
	}
}

// ===== TELEPORT ITEMS (LEVEL UP CARDS) =====
// Helper function to teleport specific item type
static void TeleportItemType(const std::string& itemClassName, const std::string& itemDisplayName)
{
	try
	{
		if (!ImGuiMenu::g_Settings.EnableTeleportLevelUpCards)
			return;
		
		APlayerController* playerController = SDK_GetPlayerController();
		if (!playerController || !playerController->Pawn)
			return;
		
		AActor* playerPawn = playerController->Pawn;
		FVector playerPos = playerPawn->K2_GetActorLocation();
		FVector forwardVector = playerPawn->GetActorForwardVector();
		
		playerPos = playerPos + (forwardVector * 200.0f);
		playerPos.Z += 100.0f;
		
		std::vector<AActor*> itemsToCopy;
		{
			std::lock_guard<std::mutex> lock(g_ItemsCacheMutex);
			for (auto& cachedActor : g_ItemsForRendering)
			{
				if (cachedActor.ClassName != itemClassName)
					continue;
				
				if (!cachedActor.ActorPtr || (uintptr_t)cachedActor.ActorPtr < 0x10000)
					continue;
				
				try
				{
					if (cachedActor.ActorPtr->IsDefaultObject())
						continue;
				}
				catch (...)
				{
					continue;
				}
				
				itemsToCopy.push_back(cachedActor.ActorPtr);
			}
		}
		
		int count = 0;
		for (auto* actorPtr : itemsToCopy)
		{
			try
			{
				FRotator dummyRotation = FRotator(0, 0, 0);
				if (actorPtr->K2_TeleportTo(playerPos, dummyRotation))
					count++;
			}
			catch (...)
			{
			}
		}
		
		if (count > 0)
		{
			char logMsg[256];
			snprintf(logMsg, sizeof(logMsg), "[TeleportItems] ✓ %s: %d items teleported", itemDisplayName.c_str(), count);
			Logger::LogInfo(logMsg);
		}
	}
	catch (...)
	{
	}
}

